const { execSync } = require('child_process');
const platform = process.platform;
const service = params.service || '';
const action = params.action || 'status';
if (platform === 'darwin') {
  if (action === 'status') {
    const result = execSync(`launchctl list | grep ${service} || true`, { encoding: 'utf-8', timeout: 10000 });
    return { output: result || 'Service not found', platform: 'macOS' };
  } else if (action === 'list') {
    const result = execSync('launchctl list | head -30', { encoding: 'utf-8', timeout: 10000 });
    return { output: result, platform: 'macOS' };
  }
} else {
  const allowed = ['status', 'list-units', 'is-active', 'is-enabled'];
  if (!allowed.includes(action)) {
    throw new Error('Action not allowed: ' + action);
  }
  const cmd = service ? `systemctl ${action} ${service}` : `systemctl ${action}`;
  const result = execSync(cmd, { encoding: 'utf-8', timeout: 10000 });
  return { output: result, platform: 'Linux' };
}
throw new Error('Unsupported action/platform');
